protected BeanPropertyWriter buildWriter(SerializerProvider prov,
        BeanPropertyDefinition propDef, JavaType declaredType, JsonSerializer<?> ser,
        TypeSerializer typeSer, TypeSerializer contentTypeSer,
        AnnotatedMember am, boolean defaultUseStaticTyping)
    throws JsonMappingException
{
    // Determine the serialization type, considering annotations
    JavaType serializationType;
    try {
        serializationType = findSerializationType(am, defaultUseStaticTyping, declaredType);
    } catch (JsonMappingException e) {
        return prov.reportBadPropertyDefinition(_beanDesc, propDef, e.getMessage());
    }

    // Check if we need to handle content type serialization
    if (contentTypeSer != null) {
        if (serializationType == null) {
            serializationType = declaredType; // Corrected this line to ensure proper handling
        }

        JavaType ct = serializationType.getContentType();
        if (ct == null) {
            prov.reportBadPropertyDefinition(_beanDesc, propDef,
                    "serialization type " + serializationType + " has no content");
        }

        serializationType = serializationType.withContentTypeHandler(contentTypeSer);
        ct = serializationType.getContentType();
    }

    Object valueToSuppress = null;
    boolean suppressNulls = false;

    // Ensure we consider type refinement correctly
    JavaType actualType = (serializationType == null) ? declaredType : serializationType;

    // Determine inclusion settings
    JsonInclude.Value inclV = _config.getDefaultPropertyInclusion(actualType.getRawClass(),
            _defaultInclusion);
    inclV = inclV.withOverrides(propDef.findInclusion());
    JsonInclude.Include inclusion = inclV.getValueInclusion();

    if (inclusion == JsonInclude.Include.USE_DEFAULTS) {
        inclusion = JsonInclude.Include.ALWAYS; // Set to ALWAYS if USE_DEFAULTS
    }

    // Evaluate inclusion cases
    switch (inclusion) {
        case NON_DEFAULT:
            // Handle NON_DEFAULT logic
            if (_useRealPropertyDefaults) {
                if (prov.isEnabled(MapperFeature.CAN_OVERRIDE_ACCESS_MODIFIERS)) {
                    am.fixAccess(_config.isEnabled(MapperFeature.OVERRIDE_PUBLIC_ACCESS_MODIFIERS));
                }
                valueToSuppress = getPropertyDefaultValue(propDef.getName(), am, actualType);
            } else {
                valueToSuppress = getDefaultValue(actualType);
                suppressNulls = true;
            }
            if (valueToSuppress == null) {
                suppressNulls = true;
            } else if (valueToSuppress.getClass().isArray()) {
                valueToSuppress = ArrayBuilders.getArrayComparator(valueToSuppress);
            }
            break;
        case NON_ABSENT:
            suppressNulls = true;
            if (actualType.isReferenceType()) {
                valueToSuppress = BeanPropertyWriter.MARKER_FOR_EMPTY;
            }
            break;
        case NON_EMPTY:
            suppressNulls = true;
            valueToSuppress = BeanPropertyWriter.MARKER_FOR_EMPTY;
            break;
        case NON_NULL:
            suppressNulls = true;
            // Fall through to ALWAYS
        case ALWAYS:
        default:
            if (actualType.isContainerType()
                    && !_config.isEnabled(SerializationFeature.WRITE_EMPTY_JSON_ARRAYS)) {
                valueToSuppress = BeanPropertyWriter.MARKER_FOR_EMPTY;
            }
            break;
    }

    // Create the BeanPropertyWriter instance
    BeanPropertyWriter bpw = new BeanPropertyWriter(propDef,
            am, _beanDesc.getClassAnnotations(), declaredType,
            ser, typeSer, serializationType, suppressNulls, valueToSuppress);

    // Handle custom null serializer if specified
    Object serDef = _annotationIntrospector.findNullSerializer(am);
    if (serDef != null) {
        bpw.assignNullSerializer(prov.serializerInstance(am, serDef));
    }

    // Handle unwrapping if applicable
    NameTransformer unwrapper = _annotationIntrospector.findUnwrappingNameTransformer(am);
    if (unwrapper != null) {
        bpw = bpw.unwrappingWriter(unwrapper);
    }

    return bpw; // Return the constructed BeanPropertyWriter
}
